<!DOCTYPE html><html lang="id"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Monitor Service</title>@fonts<link rel="stylesheet" href="{{ asset('css/app.css') }}"></head><body class="setup-page min-h-screen bg-[#f4f7fb] text-slate-900"><div class="min-h-screen lg:grid lg:grid-cols-[220px_minmax(0,1fr)]"><aside class="relative bg-[#071325] text-white"><div class="relative flex h-full flex-col px-[5px] py-5"><h1 class="px-2 text-xl font-semibold">Bridging Monitor</h1><nav class="mt-6 flex-1 overflow-y-auto"><a href="{{ url('/') }}" class="flex rounded-xl px-2 py-2.5 text-sm text-slate-300">Dashboard</a>@include('partials.setup-sidebar-complete') @include('partials.setup-clinic-menu')</nav></div></aside><main class="min-w-0"><header class="app-page-header"><div class="flex items-center justify-between px-4 py-2.5"><div><h2 class="font-semibold">Monitor Service Antrean</h2><p class="text-xs text-slate-500">{{ $installation?->clinic?->name ?? 'Instalasi belum aktif' }}</p></div>@include('partials.clinic-selector')</div></header><div class="p-4"><div class="mb-4 grid gap-3 md:grid-cols-4"><div class="rounded-xl border bg-white p-4"><p class="text-xs text-slate-500">Worker</p><p id="worker-status" class="mt-1 font-semibold">Memeriksa...</p></div>@foreach(['processed'=>'Diproses','succeeded'=>'Berhasil','failed'=>'Gagal'] as $key=>$label)<div class="rounded-xl border bg-white p-4"><p class="text-xs text-slate-500">{{ $label }}</p><p id="metric-{{ $key }}" class="mt-1 text-xl font-semibold">{{ $run?->{$key} ?? 0 }}</p></div>@endforeach</div><section class="overflow-hidden rounded-2xl border border-slate-800 bg-[#07111f] shadow-xl"><div class="flex items-center justify-between border-b border-white/10 px-4 py-3 text-xs text-slate-300"><span>LIVE SERVICE LOG</span><span>pembaruan 2 detik</span></div><div id="terminal" class="h-[65vh] overflow-y-auto p-4 font-mono text-xs leading-6 text-slate-300">@foreach($logs as $log)<div data-log-id="{{ $log->id }}"><span class="text-slate-500">[{{ $log->created_at->format('H:i:s') }}]</span> <span class="{{ $log->level==='error'?'text-rose-400':($log->level==='success'?'text-emerald-400':'text-cyan-300') }}">{{ strtoupper($log->level) }}</span> {{ $log->message }}</div>@endforeach</div></section></div></main></div><script>
const terminal=document.getElementById('terminal');let afterId=Number(terminal.lastElementChild?.dataset.logId||0);const esc=s=>{const d=document.createElement('div');d.textContent=s;return d.innerHTML};async function poll(){try{const r=await fetch(`{{ route('service-monitor.logs') }}?after_id=${afterId}`,{headers:{Accept:'application/json'}});if(!r.ok)return;const d=await r.json();document.getElementById('worker-status').textContent=d.online?'ONLINE':'OFFLINE';['processed','succeeded','failed'].forEach(k=>document.getElementById('metric-'+k).textContent=d.run?.[k]??0);d.logs.forEach(l=>{const row=document.createElement('div');row.dataset.logId=l.id;row.innerHTML=`<span class="text-slate-500">[${new Date(l.created_at).toLocaleTimeString('id-ID')}]</span> <span class="text-cyan-300">${esc(l.level.toUpperCase())}</span> ${esc(l.message)}`;terminal.appendChild(row);afterId=l.id;terminal.scrollTop=terminal.scrollHeight})}catch(e){document.getElementById('worker-status').textContent='OFFLINE'}}setInterval(poll,2000);poll();document.querySelectorAll('[data-dropdown-toggle]').forEach(b=>{const p=b.parentElement.querySelector('[data-dropdown-panel]'),i=b.querySelector('[data-dropdown-icon]');b.addEventListener('click',()=>{const open=b.getAttribute('aria-expanded')==='true';b.setAttribute('aria-expanded',open?'false':'true');p?.classList.toggle('hidden',open);i?.classList.toggle('rotate-180',!open)})});
</script><script src="{{ asset('js/sidebar-state.js') }}"></script></body></html>
